import { useEffect, useRef, useState, useMemo } from 'react';
import { MonitorPlay } from 'lucide-react';

// High-Impact Smart Scaler: Maximizes visibility while maintaining professional 'Golden' proportions
function AutoFitLyrics({ lines, isMaster = false, isLiveBroadcast = false, isClearText = false }) {
  const containerRef = useRef(null);
  const textRef = useRef(null);
  const [fontSize, setFontSize] = useState(20);

  // Standard safe-zone padding (10% all around for High-Impact screens)
  const isHighImpact = isMaster || isLiveBroadcast;
  const paddingClass = isHighImpact ? "px-[10%] py-[10%]" : "p-4";
  const opacityClass = isClearText ? "opacity-0" : "opacity-100";

  useEffect(() => {
    const fit = () => {
      const container = containerRef.current;
      const text = textRef.current;
      if (!container || !text) return;

      // Golden Proportions: Target ~10.5% of height, but shrink-to-fit if required
      const idealGoldenSize = container.clientHeight * 0.105; 
      
      // Available area for the text block (80% width/height for High Impact safe zones)
      const maxW = container.clientWidth * (isHighImpact ? 0.8 : 0.95);
      const maxH = container.clientHeight * (isHighImpact ? 0.8 : 0.9);
      
      // Binary Search: Target idealGoldenSize but shrink if it overflows max area
      let lo = 8, hi = idealGoldenSize, best = 8;
      
      while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        text.style.fontSize = mid + 'px';
        
        // Measure the block's natural scroll dimensions against available area
        if (text.scrollWidth <= maxW && text.scrollHeight <= maxH) {
          best = mid;
          lo = mid + 1;
        } else {
          hi = mid - 1;
        }
      }
      setFontSize(best);
    };

    const ro = new ResizeObserver(fit);
    if (containerRef.current) ro.observe(containerRef.current);
    fit();
    return () => ro.disconnect();
  }, [lines, isHighImpact]);

  return (
    <div ref={containerRef} className={`absolute inset-0 flex items-center justify-center overflow-hidden transition-opacity duration-300 ${paddingClass} ${opacityClass}`}>
      <div 
         ref={textRef} 
         className="font-black text-white text-center leading-[1.2] drop-shadow-[0_4px_48px_rgba(0,0,0,1)] w-full antialiased" 
         style={{ fontSize: fontSize + 'px' }}
      >
        {lines.map((line, i) => <div key={i}>{line}</div>)}
      </div>
    </div>
  );
}

// FixedLyrics is now just an alias for high-impact AutoFit for backwards compatibility
function FixedLyrics({ lines, isClearText = false }) {
  return <AutoFitLyrics lines={lines} isMaster={true} isClearText={isClearText} />;
}

export default function OutputScreen({ payload, isMaster = false, isLiveBroadcast = false, onStatusUpdate = null, remoteCommand = null }) {
    const videoRef = useRef(null);
    const iframeRef = useRef(null);
    const isMutingReports = useRef(false);
    const lastReportTime = useRef(0);
    const lastReportedPaused = useRef(true);

    // YouTube Follower Tracking State
    const followerTimeRef = useRef(0);
    const followerDurationRef = useRef(0);
    const followerPausedRef = useRef(true);
    const lastSentPauseRef = useRef(null);
    const lastUrlRef = useRef("");

    const isMuted = !isMaster || isLiveBroadcast; // Always mute for viewers and previews
    const lastHandledCommandTs = useRef(0);

    // 1. Reactive Command Handler (Responds to props from ProjectorWindow or App)
    useEffect(() => {
        if (!remoteCommand || remoteCommand.ts === lastHandledCommandTs.current) return;
        lastHandledCommandTs.current = remoteCommand.ts;

        const { command, value, isYoutube, isVimeo } = remoteCommand;
        
        // Mute status reporting briefly to prevent feedback loops during seeking
        isMutingReports.current = true;

        // Handle HTML5 Video
        if (videoRef.current) {
           const v = videoRef.current;
           if (command === 'play') v.play().catch(() => { v.muted = true; v.play().catch(() => {}); });
           if (command === 'pause') v.pause();
           if (command === 'seek') v.currentTime = value;
           if (command === 'volume' && (isMaster || !onStatusUpdate)) {
              v.volume = value;
              if (value > 0) v.muted = false;
              else v.muted = true;
           }
        }

        // Handle YouTube/Vimeo Iframe
        if (iframeRef.current && (isYoutube || isVimeo)) {
           let message = '';
           if (isYoutube) {
              if (command === 'play') message = JSON.stringify({ event: 'command', func: 'playVideo' });
              else if (command === 'pause') message = JSON.stringify({ event: 'command', func: 'pauseVideo' });
              else if (command === 'seek') message = JSON.stringify({ event: 'command', func: 'seekTo', args: [value, true] });
              else if (command === 'volume') message = JSON.stringify({ event: 'command', func: 'setVolume', args: [value * 100] });
           } else if (isVimeo) {
              if (command === 'play') message = JSON.stringify({ method: 'play' });
              else if (command === 'pause') message = JSON.stringify({ method: 'pause' });
              else if (command === 'seek') message = JSON.stringify({ method: 'setCurrentTime', value: value });
              else if (command === 'volume') message = JSON.stringify({ method: 'setVolume', value: value });
           }
           if (message) iframeRef.current.contentWindow?.postMessage(message, '*');
        }

        const timeout = setTimeout(() => { 
            isMutingReports.current = false; 
            // Force status sync immediately after mute period ends to fix Network Viewers missing updates
            if (isMaster && onStatusUpdate && videoRef.current) {
                onStatusUpdate({
                    time: videoRef.current.currentTime,
                    duration: videoRef.current.duration || 0,
                    paused: videoRef.current.paused
                });
            }
        }, 300);
        return () => clearTimeout(timeout);
    }, [remoteCommand, isMaster, onStatusUpdate]);

    // Maintain a live reference to the latest payload to avoid stale closures in the handleMessage event listener
    const payloadRef = useRef(payload);
    useEffect(() => {
        payloadRef.current = payload;
    }, [payload]);

    // 2. Status Polling & Listener for Dashboard (YouTube/Vimeo)
    useEffect(() => {
       if (!onStatusUpdate) return; // Allow both Projector and Followers to listen for iframe ready-signals

       const handleMessage = (event) => {
          if (isMutingReports.current) return;
          try {
             const data = typeof event.data === 'string' ? JSON.parse(event.data) : event.data;
             const freshPayload = payloadRef.current;
             if (data.event === 'infoDelivery' && data.info) {
                const info = data.info;
                                // Track internally for Follower mode sync without depending on React state
                 if (info.currentTime !== undefined) followerTimeRef.current = info.currentTime;
                 if (info.duration !== undefined && info.duration > 0) followerDurationRef.current = info.duration;
                 if (info.playerState !== undefined) followerPausedRef.current = (info.playerState !== 1);
                 
                 // Broadcast status using the persistent refs instead of functional updates
                 // This guarantees duration isn't wiped if a secondary infoDelivery pulse is missing the duration key
                 onStatusUpdate({
                    time: followerTimeRef.current,
                    duration: followerDurationRef.current,
                    paused: followerPausedRef.current,
                    ts: Date.now()
                 });
              }
             if (data.event === 'ready' && iframeRef.current) {
                iframeRef.current.contentWindow?.postMessage(JSON.stringify({ method: 'addEventListener', value: 'playProgress' }), '*');
                iframeRef.current.contentWindow?.postMessage(JSON.stringify({ method: 'addEventListener', value: 'loaded' }), '*');
                
                // Auto-bootstrap playback if we were pushed live in a playing state
                // This defeats the race condition where the 'play' remote command arrives before the iframe is bootstrapped
                if (freshPayload && !freshPayload.isPaused) {
                   const playMsg = JSON.stringify(freshPayload.isVimeo ? { method: 'play' } : { event: 'command', func: 'playVideo' });
                   iframeRef.current.contentWindow?.postMessage(playMsg, '*');
                   
                   // Force Network Followers to physically seek to the Master Playhead instantly on startup!
                   // This prevents Youtube/Vimeo network views from starting at 0:00 and remaining 'slightly out of sync' for 2 seconds.
                   if (freshPayload.currentTime > 0.5 && !isMaster) {
                       const seekMsg = JSON.stringify(freshPayload.isVimeo ? { method: 'setCurrentTime', value: freshPayload.currentTime } : { event: 'command', func: 'seekTo', args: [freshPayload.currentTime, true] });
                       iframeRef.current.contentWindow?.postMessage(seekMsg, '*');
                   }
                   
                   // Restore volume over API once playing (bypasses Chrome Autoplay limitations)
                   if (freshPayload.isVimeo && !isMuted) {
                       const volMsg = JSON.stringify({ method: 'setVolume', value: freshPayload.volume !== undefined ? freshPayload.volume : 1 });
                       setTimeout(() => iframeRef.current?.contentWindow?.postMessage(volMsg, '*'), 500);
                   }
                }
             }
             if (data.event === 'loaded' && data.data && freshPayload?.isVimeo) {
                onStatusUpdate({ duration: data.data.duration });
             }
             if (data.event === 'playProgress' && data.data) {
                onStatusUpdate({ time: data.data.seconds, duration: data.data.duration, paused: false });
             }
          } catch (e) {}
       };

       window.addEventListener('message', handleMessage);
       const poll = setInterval(() => {
          if (iframeRef.current && payloadRef.current?.isYouTube) {
             iframeRef.current.contentWindow?.postMessage(JSON.stringify({ event: 'listening' }), '*');
          }
       }, 1000);

       return () => {
          window.removeEventListener('message', handleMessage);
          clearInterval(poll);
       };
    }, [isMaster, onStatusUpdate, payloadRef.current?.isYouTube]);

    // 3. Status Reporting & Follower Sync Logic
    const reportStatus = () => {
        // Master Mode: Designated component reports status to the system
        if (!onStatusUpdate || !videoRef.current || isMutingReports.current) return;
        if (!isMaster) return; // ONLY the Master acts as the source of truth
        
        const v = videoRef.current;
        const now = Date.now();
        
        // Mask the HTML5 Buffering Phase: 
        // If Dashboard issued PLAY (!payload.isPaused), but the hardware hasn't actually started playing yet (e.g., during onLoadedMetadata), 
        // DO NOT report 'paused: true' back to the dashboard, as this overrides the Play button back to a Pause icon!
        const isTemporarilyBuffering = payload && !payload.isPaused && v.paused && v.currentTime < v.duration;
        const reportedPaused = isTemporarilyBuffering ? false : v.paused;

        // Anti-stutter: Throttle continuous time reports to ~2Hz when playing naturally.
        if (now - lastReportTime.current < 500 && reportedPaused === lastReportedPaused.current) return;
        
        lastReportTime.current = now;
        lastReportedPaused.current = reportedPaused;

        onStatusUpdate({
            time: v.currentTime,
            duration: v.duration || 0,
            paused: reportedPaused,
            volume: v.volume,
            ts: Date.now()
        });
    };

    // Follower Sync Logic: If we are a Follower (Phone or Dashboard), we shadow the Master's playhead
    useEffect(() => {
       // Reset refs ONLY on media change to prevent timeline ghosting
       if (payload?.activeMediaUrl && payload.activeMediaUrl !== lastUrlRef.current) {
           lastUrlRef.current = payload.activeMediaUrl;
           followerTimeRef.current = 0;
           followerDurationRef.current = 0;
       }

       // Don't follow if we are the master
       if (isMaster || !payload) return;

       // 1. HTML5 Local Video Sync
       if (videoRef.current && payload.currentTime !== undefined) {
           const v = videoRef.current;
           
           // Interpolate real-time position based on payload transmission latency
           let targetTime = payload.currentTime + ((Date.now() - (payload.currentTimeTs || Date.now())) / 1000);
           
           const diff = v.currentTime - targetTime;
           const absDiff = Math.abs(diff);
           
           if (absDiff > 0.5) {
               v.currentTime = targetTime;
               v.playbackRate = 1.0;
           } else if (!payload.isPaused) {
               // Soft sync rubber-banding for imperceptible convergence!
               if (absDiff > 0.25) {
                   v.playbackRate = diff > 0 ? 0.85 : 1.15; // Gentle convergence
               } else {
                   v.playbackRate = 1.0;
               }
           }
           
           if (payload.isPaused !== undefined && payload.isPaused !== lastSentPauseRef.current) {
              lastSentPauseRef.current = payload.isPaused;
              if (payload.isPaused && !v.paused) {
                 v.pause();
                 v.playbackRate = 1.0;
              } else if (!payload.isPaused && v.paused) {
                 v.play().catch(() => {});
              }
           }
       }
       
       // 2. YouTube / Vimeo External Iframe Sync
       if (iframeRef.current && (payload.isYouTube || payload.isVimeo) && payload.currentTime !== undefined) {
           // Fall back to pure absolute network payload timestamp without Date.now() time-drift calculations
           let targetTime = payload.currentTime + ((Date.now() - (payload.currentTimeTs || Date.now())) / 1000);

           // Enforce time sync if drifted more than 2 seconds (YouTube doesn't support playback rate tuning easily through postMessage API)
           const diff = Math.abs(followerTimeRef.current - targetTime);
           if (diff > 2.0) {
              const msg = JSON.stringify({ event: 'command', func: 'seekTo', args: [targetTime, true] });
              iframeRef.current.contentWindow?.postMessage(msg, '*');
              followerTimeRef.current = targetTime; // Optimistic update to prevent seek looping
           }
           
           // Enforce Play/Pause State with API throttle to completely eliminate Youtube/Vimeo lag
           if (payload.isPaused !== undefined && payload.isPaused !== lastSentPauseRef.current) {
              lastSentPauseRef.current = payload.isPaused;
              const msg = JSON.stringify(
                 payload.isVimeo ? { method: payload.isPaused ? 'pause' : 'play' }
                                 : { event: 'command', func: payload.isPaused ? 'pauseVideo' : 'playVideo' }
              );
              iframeRef.current.contentWindow?.postMessage(msg, '*');
           }
       }
    }, [isMaster, payload?.currentTime, payload?.isPaused]);

    // Display Guard: Determine if we should show live content or standby
    const isNetworkViewer = payload?.isNetworkViewer; // Set in App.jsx network broadcast
    const isDashboardPreview = !isMaster && !isNetworkViewer;
    const shouldShowLiveContent = payload?.isLive || isDashboardPreview || payload?.isBlackScreen || payload?.isShowLogo;

    if (!payload || !shouldShowLiveContent) {
       return (
         <div className="w-full h-full bg-black flex flex-col items-center justify-center p-12 text-center animate-in fade-in duration-700 select-none">
           <div className="relative group">
              <div className="absolute inset-0 bg-blue-600/30 blur-[120px] rounded-full animate-pulse transition-all duration-1000" />
              <h1 className="text-[12cqw] font-black tracking-[0.2em] text-white uppercase relative z-10 drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]">
                 Halos
              </h1>
           </div>
           
           <div className="mt-12 flex flex-col items-center gap-6">
              <div className="flex items-center gap-4 bg-white/10 px-8 py-4 rounded-2xl border-2 border-white/20 backdrop-blur-md shadow-2xl">
                 <div className="w-3 h-3 rounded-full bg-blue-400 animate-ping" />
                 <span className="text-sm font-black uppercase tracking-[0.5em] text-white">Projector Connected</span>
              </div>
              <p className="text-neutral-400 font-bold uppercase tracking-[0.3em] text-xs">Waiting for live content...</p>
           </div>
         </div>
       );
    }
  
    return (
      <div className="w-full h-full bg-black overflow-hidden relative font-sans">
         {!payload?.isBlackScreen && !payload?.isShowLogo && (
            (payload?.activeSlide?.length > 0 || payload?.activeMediaUrl) ? (
               <>
                  {(payload.mediaType === 'image' || payload.mediaType === 'slide_deck') && payload.activeMediaUrl && (
                     <img src={payload.activeMediaUrl} className="w-full h-full object-contain animate-in fade-in duration-500 pointer-events-none" />
                  )}
                  {payload.mediaType === 'video' && payload.activeMediaUrl && (
                     (payload.isYouTube || payload.isVimeo) ? (
                       <iframe 
                         ref={iframeRef}
                         // Force muted=1 on initial load if we want autoplay OR if it's Vimeo (Vimeo strictly blocks script-driven play unless initially muted)
                         src={`${payload.activeMediaUrl}${payload.activeMediaUrl?.includes('?') ? '&' : '?'}autoplay=${payload.itemAutoPlay ? 1 : 0}&enablejsapi=1&api=1&controls=0&mute=${isMuted ? 1 : 0}&muted=${(isMuted || payload.isVimeo) ? 1 : (payload.itemAutoPlay ? 1 : 0)}`} 
                         className="w-full h-full rounded-lg pointer-events-none" 
                         frameBorder="0" 
                         allow={`autoplay; fullscreen; picture-in-picture; encrypted-media`}
                         allowFullScreen
                       />
                     ) : (
                       <video 
                         ref={videoRef}
                         src={payload.activeMediaUrl} 
                         autoPlay={payload.itemAutoPlay}
                         muted={isMuted} 
                         loop 
                         onTimeUpdate={reportStatus}
                         onPlay={reportStatus}
                         onPause={reportStatus}
                         onLoadedMetadata={(e) => {
                             reportStatus();
                             if (!isMaster && payload?.currentTime !== undefined) {
                                 e.target.currentTime = payload.currentTime;
                                 if (payload.isPaused) e.target.pause();
                             }
                         }}
                         onLoadedData={reportStatus}
                         onDurationChange={reportStatus}
                         className="w-full h-full object-contain animate-in fade-in duration-500 pointer-events-none" 
                       />
                     )
                  )}
                  {payload.activeSlide && payload.activeSlide.length > 0 && (
                     (isMaster || isLiveBroadcast)
                        ? <FixedLyrics lines={payload.activeSlide} linesPerSlide={payload.linesPerSlide} isClearText={payload.isClearText} />
                        : <AutoFitLyrics lines={payload.activeSlide} isClearText={payload.isClearText} />
                  )}
               </>
            ) : (
               /* Standby / Holding Screen (Mirrored across Projector and Live Viewer) */
               <div className="flex flex-col items-center justify-center text-center animate-in fade-in duration-1000 w-full h-full bg-black">
                  <div className="relative">
                     <div className="absolute inset-0 bg-blue-600/20 blur-[120px] rounded-full animate-pulse transition-all duration-1000" />
                     <h1 className="text-[12cqw] font-black tracking-[0.2em] text-white uppercase select-none relative z-10 drop-shadow-[0_0_30px_rgba(59,130,246,0.3)]">
                        Halos
                     </h1>
                  </div>
                  <div className="mt-8 flex flex-col items-center gap-4">
                     <div className="flex items-center gap-3 bg-white/5 px-6 py-2.5 rounded-full border border-white/10 backdrop-blur-md">
                        <div className="w-2 h-2 rounded-full bg-blue-400 animate-pulse" />
                        <span className="text-[10px] font-black uppercase tracking-[0.4em] text-white/60">System Standby</span>
                     </div>
                  </div>
               </div>
            )
         )}
         {payload?.isBlackScreen && <div className="absolute inset-0 bg-black z-40" />}
         {payload?.isShowLogo && payload?.logoUrl && !payload?.isBlackScreen && (
            <div className="absolute inset-0 bg-black z-30 flex items-center justify-center">
               <img src={payload.logoUrl} className="w-full h-full object-contain animate-in zoom-in-95" />
            </div>
         )}
      </div>
    );
}

import { Edit3, CheckCircle, Circle, Plus, Minus } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

/**
 * UniformTile: renders slide text at a fixed 18px font size for perfect continuity.
 */
function UniformTile({ lines }) {
  return (
    <div className="flex-1 w-full flex items-center justify-center overflow-hidden px-4 py-2">
      <div
        className="font-black text-white text-center leading-tight tracking-tight drop-shadow-2xl w-full"
        style={{ fontSize: '18px', whiteSpace: 'pre-wrap' }}
      >
        {lines.map((line, i) => (
          <div key={i}>{line}</div>
        ))}
      </div>
    </div>
  );
}

export default function PreviewEditor({ 
  item, 
  activeIndex, 
  selectedIndices = new Set(),
  isServiceItem = false,
  onToggleSelection,
  onSelectIndex, 
  onEdit, 
  onAddSelectedToService,
  onRemoveSelectedFromService,
  linesPerSlide = 2, 
  onChangeLinesPerSlide 
}) {
  const tileRefs = useRef([]);

  // Auto-scroll the active tile into view on keyboard navigation
  useEffect(() => {
    if (tileRefs.current[activeIndex]) {
      tileRefs.current[activeIndex].scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }, [activeIndex]);

  if (!item) return null;

  const slides = item.slides || [];
  const title = item.title || item.reference || 'Untitled';
  const subtitle = item.artist
    ? `${item.artist}${item.ccli ? ` | CCLI #${item.ccli}` : ''}`
    : (item.translation || '');
  const isSong = item.type === 'song';

  const handleAddSelected = () => {
    onAddSelectedToService();
  };

  const handleRemoveSelected = () => {
    onRemoveSelectedFromService();
  };

  return (
    <div className="flex flex-col h-full animate-in fade-in duration-300">
      {/* Header */}
      <div className="flex justify-between items-start mb-6 border-b border-neutral-800/50 pb-4">
        <div className="flex flex-col">
          <h2 className="text-3xl font-extrabold text-white tracking-tight">{title}</h2>
          {subtitle && (
            <div className="text-sm font-bold text-neutral-400 mt-2 uppercase tracking-widest leading-none">
              {subtitle}
            </div>
          )}
        </div>

        <div className="flex items-center gap-3">
          {/* Dynamic "Add/Remove Selected" Button */}
          {selectedIndices.size > 0 && (
            isServiceItem ? (
              <button
                onClick={handleRemoveSelected}
                className="flex items-center gap-2 px-6 py-2 bg-red-600 hover:bg-red-500 text-white rounded-xl transition-all font-black text-xs uppercase tracking-widest shadow-lg shadow-red-900/20 active:scale-95"
              >
                <Minus size={16} strokeWidth={3} />
                Remove Selected ({selectedIndices.size})
              </button>
            ) : (
              <button
                onClick={handleAddSelected}
                className="flex items-center gap-2 px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all font-black text-xs uppercase tracking-widest shadow-lg shadow-blue-900/20 active:scale-95"
              >
                <Plus size={16} strokeWidth={3} />
                Add Selected ({selectedIndices.size})
              </button>
            )
          )}

          {/* Lines per slide toggle ÔÇö only for songs */}
          {isSong && onChangeLinesPerSlide && (
            <div className="flex items-center gap-1 bg-neutral-900 border border-neutral-800 rounded-xl overflow-hidden p-1">
              <span className="text-[9px] font-black uppercase tracking-widest text-neutral-400 px-2">Lines</span>
              {[1, 2, 3, 4].map(n => (
                <button
                  key={n}
                  onClick={() => onChangeLinesPerSlide(n)}
                  className={`w-8 h-7 text-xs font-black rounded-lg transition-all ${
                    linesPerSlide === n
                      ? 'bg-blue-600 text-white shadow-[0_0_10px_rgba(59,130,246,0.4)]'
                      : 'text-neutral-400 hover:text-white hover:bg-neutral-700'
                  }`}
                >
                  {n}
                </button>
              ))}
            </div>
          )}

          {isSong && onEdit && (
            <button
              onClick={() => onEdit(item)}
              className="flex items-center gap-2 px-4 py-2 bg-neutral-800 hover:bg-neutral-700 text-neutral-300 hover:text-white rounded-xl border border-neutral-700/50 transition-all font-bold text-xs uppercase tracking-widest shadow-lg transform hover:-translate-y-0.5 active:translate-y-0"
            >
              <Edit3 size={14} className="text-blue-400" />
              Edit Song
            </button>
          )}
        </div>
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pb-32 pt-2 px-1">
        <div className="grid grid-cols-2 gap-x-8 gap-y-12">
          {slides.map((slide, i) => (
            <div key={i} ref={el => tileRefs.current[i] = el} className="flex flex-col gap-2 group">
              {/* Card */}
              <div
                onClick={() => onSelectIndex && onSelectIndex(i)}
                className={`aspect-video rounded-3xl flex flex-col relative cursor-pointer border-2 transition-all duration-300 overflow-hidden ${
                  i === activeIndex
                    ? 'bg-blue-900/10 border-blue-500 shadow-[0_0_40px_rgba(59,130,246,0.3)] scale-[1.02] transform z-10'
                    : 'bg-neutral-900/40 border-neutral-800 hover:border-neutral-700 hover:scale-[1.01] transform'
                } ${selectedIndices.has(i) ? 'border-blue-500/50' : ''}`}
              >
                <UniformTile lines={slide.content || []} />

                {/* Selection Indicator */}
                <div 
                  onClick={(e) => { e.stopPropagation(); onToggleSelection(i); }}
                  className={`absolute top-4 right-4 w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 ${
                    selectedIndices.has(i) 
                      ? 'bg-blue-600 text-white scale-110 shadow-lg' 
                      : 'bg-black/40 text-white/40 hover:bg-black/60 hover:text-white opacity-0 group-hover:opacity-100'
                  }`}
                >
                  {selectedIndices.has(i) ? <CheckCircle size={20} /> : <Circle size={20} />}
                </div>
              </div>

              {/* Label Row */}
              <div className="flex justify-between items-center px-4">
                <div className={`text-[10px] font-black uppercase tracking-[0.3em] transition-colors ${
                  i === activeIndex || selectedIndices.has(i) ? 'text-blue-400' : 'text-neutral-400'
                }`}>
                  {slide.type}
                </div>
                <div className={`text-[10px] font-black ${
                  i === activeIndex || selectedIndices.has(i) ? 'text-blue-500/80' : 'text-neutral-700'
                }`}>
                  SLIDE {i + 1}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState, useRef } from 'react';
import OutputScreen from './OutputScreen';

export default function ProjectorWindow() {
  const [payload, setPayload] = useState(null);
  const [remoteCommand, setRemoteCommand] = useState(null);
  const containerRef = useRef(null);
  const [scale, setScale] = useState(1);

  useEffect(() => {
    // Override page title for easier OS task management
    document.title = "Halos Projector Output";

    // Initialize high-speed background syncing (Unified Hub)
    const channel = new BroadcastChannel('halos-projector-hub');

    channel.onmessage = (e) => {
       if (!e.data) return;

       // Handle Playback Commands
       if (e.data.type === 'playback') {
          // Add a timestamp to remoteCommand to ensure it triggers useEffect in OutputScreen even if same command is sent
          setRemoteCommand({ ...e.data, ts: Date.now() });
       } 
       // Handle Orphan Scopes
       else if (e.data.type === 'master-reboot') {
          window.location.reload();
       }
       // Handle Content Payload updates
       else if (typeof e.data === 'object' && e.data.isLive !== undefined) {
          setPayload(e.data);
       } 
    };

    // PING Main Controller Window to get initialized payload if we just opened
    channel.postMessage('ping');

    return () => channel.close();
  }, []);

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;

      const { clientWidth, clientHeight } = containerRef.current;
      const targetW = 1600;
      const targetH = 900;

      const scaleX = clientWidth / targetW;
      const scaleY = clientHeight / targetH;
      const newScale = Math.min(scaleX, scaleY);

      setScale(newScale);
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial call

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <div ref={containerRef} className="w-screen h-screen bg-black overflow-hidden flex items-center justify-center">
        <div style={{ width: '1600px', height: '900px', transform: "$"scale($scale)", transformOrigin: 'center center' }}>
           <OutputScreen 
             payload={payload} 
             isMaster={false} 
             remoteCommand={remoteCommand}
           />
        </div>
    </div>
  );
}

import { GripVertical, Trash2, Save, Upload, Eraser, PlayCircle, CheckCircle, RotateCcw } from 'lucide-react';
import { useState } from 'react';
export default function ServiceFlow({ items, onReorder, onSelect, onRemove, onUpdate, onSave, onLoad, onClear, liveItemId, playedItems, onResetPlayed, onResetItemPlayed }) {
  const [draggedIdx, setDraggedIdx] = useState(null);

  const handleDragStart = (e, index) => {
    setDraggedIdx(index);
    // Allow move effect
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e, targetIdx) => {
    e.preventDefault();
    if (draggedIdx === null || draggedIdx === targetIdx) return;

    const newItems = [...items];
    const item = newItems.splice(draggedIdx, 1)[0];
    newItems.splice(targetIdx, 0, item);

    setDraggedIdx(targetIdx);
    onReorder(newItems);
  };

  const handleDragEnd = () => {
    setDraggedIdx(null);
  };

  const Header = () => (
    <div className="flex flex-col gap-3 mb-4 px-1">
      <h2 className="text-[10px] font-bold text-neutral-500 uppercase tracking-widest leading-none block">Service Flow</h2>
      <div className="grid grid-cols-4 gap-1.5">
         <button 
           onClick={onClear}
           title="Clear Service"
           className="p-2 flex flex-col items-center justify-center gap-1.5 bg-neutral-800/80 hover:bg-neutral-700 text-neutral-400 hover:text-red-400 border border-neutral-700/50 rounded-lg transition text-[8px] font-black uppercase tracking-widest text-center shadow-lg"
         >
           <Eraser size={14} /> Clear
         </button>
         <button 
           onClick={onResetPlayed}
           title="Reset All Statuses"
           className="p-2 flex flex-col items-center justify-center gap-1.5 bg-neutral-800/80 hover:bg-neutral-700 text-neutral-400 hover:text-white border border-neutral-700/50 rounded-lg transition text-[8px] font-black uppercase tracking-widest text-center shadow-lg"
         >
           <RotateCcw size={14} /> Reset
         </button>
         <button 
           onClick={onLoad}
           title="Load Service"
           className="p-2 flex flex-col items-center justify-center gap-1.5 bg-neutral-800/80 hover:bg-neutral-700 text-neutral-400 hover:text-blue-400 border border-neutral-700/50 rounded-lg transition text-[8px] font-black uppercase tracking-widest text-center shadow-lg"
         >
           <Upload size={14} /> Load
         </button>
         <button 
           onClick={onSave}
           title="Save Service"
           className="p-2 flex flex-col items-center justify-center gap-1.5 bg-neutral-800/80 hover:bg-neutral-700 text-neutral-400 hover:text-green-400 border border-neutral-700/50 rounded-lg transition text-[8px] font-black uppercase tracking-widest text-center shadow-lg"
         >
           <Save size={14} /> Save
         </button>
      </div>
    </div>
  );

  if (!items || items.length === 0) {
    return (
      <div className="flex flex-col h-full mt-2 w-full">
        <Header />
        <div className="text-sm font-medium text-neutral-400 p-6 text-center bg-neutral-900/50 rounded-2xl border border-neutral-800 border-dashed shadow-inner leading-relaxed opacity-60">
          Your service is currently empty.<br/><br/>Go to Songs, Bible, or Media tabs to search and add items to your flow.
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full w-full mt-2">
      <Header />
      <div className="flex-1 overflow-y-auto space-y-2.5 px-1 pb-4">
        {items.map((item, index) => {
          const isPlaying = liveItemId === item.id;
          const isPlayed = !isPlaying && playedItems?.has(item.id);

          return (
          <div 
            key={item.id || index}
            draggable
            onDragStart={(e) => handleDragStart(e, index)}
            onDragOver={(e) => handleDragOver(e, index)}
            onDragEnd={handleDragEnd}
            onClick={() => onSelect(item)}
            className={`p-3.5 rounded-xl flex items-center gap-3 cursor-grab active:cursor-grabbing group border transition-all shadow-md hover:shadow-lg ${
              isPlaying ? 'border-green-500/50 bg-green-900/10' : 'border-neutral-700/50 hover:border-blue-500/50 bg-neutral-800/80 hover:bg-neutral-700/90'
            } ${
              isPlayed ? 'opacity-50' : 'opacity-100'
            } ${
              draggedIdx === index ? 'opacity-30 scale-95' : 'scale-100'
            }`}
          >
            <GripVertical size={18} className="text-neutral-500 group-hover:text-blue-400 transition-colors" />
            <div className="min-w-0 flex-1">
              <div className={`font-bold text-sm truncate flex items-center gap-2 ${isPlaying ? 'text-green-400' : 'text-neutral-100'}`}>
                 {item.title || item.reference || 'Untitled Item'}
                 {isPlayed && <CheckCircle size={14} className="text-neutral-500 ml-1" />}
              </div>
              <div className="flex items-center gap-3 mt-1">
                 <div className="text-[10px] font-extrabold text-neutral-500 uppercase tracking-widest leading-none">{item.type || 'Media'}</div>

                 {(item.type === 'video' || item.type === 'slide_deck') && (
                    <button
                       onClick={(e) => {
                          e.stopPropagation();
                          onUpdate(index, { ...item, autoPlay: !item.autoPlay });
                       }}
                       className={`flex items-center gap-1 min-w-max px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest transition-all ${
                          item.autoPlay 
                             ? 'bg-blue-500/20 text-blue-400 border border-blue-500/30' 
                             : 'bg-neutral-800/80 text-neutral-500 border border-neutral-700/50 hover:text-neutral-400'
                       }`}
                       title="Auto Play when pushed Live"
                    >
                       <PlayCircle size={10} className={item.autoPlay ? 'text-blue-400' : 'text-neutral-500'} /> Auto Play
                    </button>
                 )}
              </div>
            </div>

            <div className="flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
               {isPlayed && (
                 <button 
                   onClick={(e) => {
                     e.stopPropagation();
                     if (onResetItemPlayed) onResetItemPlayed(item.id);
                   }}
                   className="p-2 hover:bg-neutral-600/50 hover:text-white text-neutral-500 rounded-lg transition-all mr-1"
                   title="Reset Status"
                 >
                   <RotateCcw size={16} />
                 </button>
               )}
               <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onRemove(index);
                  }}
                  className="p-2 hover:bg-red-500/20 hover:text-red-500 text-neutral-500 rounded-lg transition-all"
                  title="Remove from Service"
               >
                 <Trash2 size={16} />
               </button>
            </div>
          </div>
        )})}
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Search, Plus, Layers, File, Music, Image as ImgIcon, Video, FileText, CheckCircle, Check, Trash2, Sparkles } from 'lucide-react';
import BibleModule from './BibleModule';
import ServiceFlow from './ServiceFlow';
import { processBibleJson } from '../services/bibleService';
import ConfirmModal from './ConfirmModal';

export default function Sidebar({ 
  activeTab, 
  libraryHandle, 
  searchState, 
  folderFiles,
  serviceItems, 
  onServiceReorder, 
  onSelectItem, 
  onAddToService,
  onNewSong,
  onRemoveServiceItem,
  onUpdateServiceItem,
  onSaveService,
  onLoadService,
  onClearService,
  systemTrigger,
  onDeleteItem,
  liveItemId,
  playedItems,
  onResetPlayed,
  onResetItemPlayed
}) {
  const [localQuery, setLocalQuery] = useState('');
  const [showAdded, setShowAdded] = useState(false);
  const [bibleToDelete, setBibleToDelete] = useState(null);
  const [songToDelete, setSongToDelete] = useState(null);
  const [fileToDelete, setFileToDelete] = useState(null);
  const [videoUrl, setVideoUrl] = useState('');
  const [videoTitle, setVideoTitle] = useState('');
  const [isFetchingTitle, setIsFetchingTitle] = useState(false);

  // Multi-Source Integrated Search
  const [searchMode, setSearchMode] = useState('local'); // 'local', 'songselect', 'web', 'lyrics-ovh'
  const [ssResults, setSsResults] = useState([]);
  const [webResults, setWebResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const searchTimer = useRef(null);

  const triggerAddFeedback = () => {
     onAddToService();
     setShowAdded(true);
     setTimeout(() => setShowAdded(false), 2000);
  };

  const handleSearch = (e) => {
    const val = e.target.value;
    setLocalQuery(val);

    if (activeTab === 'Songs') {
      if (searchMode === 'local') {
        if (searchState && searchState.search) searchState.search(val);
      } else {
        // Debounced Global Searches
        if (searchTimer.current) clearTimeout(searchTimer.current);
        searchTimer.current = setTimeout(() => {
          if (searchMode === 'songselect') performSSSearch(val);
          if (searchMode === 'web') performUniversalSearch(val);
          if (searchMode === 'lyrics-ovh') performQuickLyricsSearch(val);
        }, 600);
      }
    }
  };

  const performSSSearch = async (q) => {
    if (!q.trim()) {
      setSsResults([]);
      return;
    }
    setIsSearching(true);
    try {
      const resp = await fetch(`/api/songselect-search?q=${encodeURIComponent(q)}`);
      const html = await resp.text();

      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const items = doc.querySelectorAll('.song-item');

      const parsed = Array.from(items).map(item => {
          const titleEl = item.querySelector('.song-item-title a');
          const subtitleEl = item.querySelector('.song-item-subtitle');
          return {
              id: titleEl?.getAttribute('href') || Math.random().toString(),
              title: titleEl?.textContent?.trim() || 'Unknown Title',
              artist: subtitleEl?.textContent?.trim() || 'Unknown Author',
              url: `https://songselect.ccli.com${titleEl?.getAttribute('href')}/viewlyrics`
          };
      });
      setSsResults(parsed);
    } catch (err) {
      console.error("SS Search failed", err);
    } finally {
      setIsSearching(false);
    }
  };

  const performUniversalSearch = async (q) => {
    if (!q.trim()) {
      setWebResults([]);
      return;
    }
    setIsSearching(true);
    try {
      const resp = await fetch(`/api/universal-search?q=${encodeURIComponent(q)}`);
      const html = await resp.text();

      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const links = doc.querySelectorAll('.result-link');

      const parsed = Array.from(links).map(link => {
          const row = link.closest('tr');
          const snippet = row?.nextElementSibling?.querySelector('.result-snippet');

          let href = link.getAttribute('href');
          // Strip DuckDuckGo's internal tracking redirect proxy
          if (href && href.includes('uddg=')) {
              try {
                  const urlObj = new URL(href, 'http://localhost');
                  href = decodeURIComponent(urlObj.searchParams.get('uddg'));
              } catch(e) {}
          }

          return {
              id: href,
              title: link.textContent?.trim() || 'Unknown Title',
              url: href,
              snippet: snippet?.textContent?.trim() || ''
          };
      });
      setWebResults(parsed);
    } catch (err) {
      console.error("Web Search failed", err);
    } finally {
      setIsSearching(false);
    }
  };

  const performQuickLyricsSearch = async (q) => {
    if (!q.trim()) return;
    setIsSearching(true);
    try {
      // Try to split artist and title if possible, otherwise treat as title
      let artist = 'Various';
      let title = q;
      let hasFormat = false;
      if (q.includes('-')) {
         [artist, title] = q.split('-').map(s => s.trim());
         hasFormat = true;
      } else if (q.toLowerCase().includes(' by ')) {
         [title, artist] = q.toLowerCase().split(' by ').map(s => s.trim());
         hasFormat = true;
      }

      if (!hasFormat) {
         setWebResults([{
             id: 'format-tip',
             title: 'Quick Search requires Artist - Title',
             url: '#',
             snippet: 'Example: "Brandon Lake - Gratitude" or "Gratitude by Brandon Lake". (Lyrics.ovh API requires splitting the artist and title).'
         }]);
         return;
      }

      const resp = await fetch(`/api/lyrics-ovh?artist=${encodeURIComponent(artist)}&title=${encodeURIComponent(title)}`);
      if (resp.ok) {
        const data = await resp.json();
        if (data.lyrics) {
          // Open in a virtual "Magic Import" view or just log it
          // For now, let's just create a single result card
          setWebResults([{ 
              id: 'ovh-match', 
              title: `${title} (${artist})`, 
              url: 'virtual:lyrics-ovh', 
              content: data.lyrics,
              snippet: 'Found direct lyrics match! Click to import.' 
          }]);
        } else {
          setWebResults([{
             id: 'no-match',
             title: 'No direct lyrics found in DB',
             url: '#',
             snippet: 'Try using the Global Web Search tab instead to scrape Google/DuckDuckGo.'
          }]);
        }
      }
    } catch (err) {
      console.error("Lyrics.ovh failed", err);
    } finally {
      setIsSearching(false);
    }
  };

  const handleOpenExternalLyrics = (res) => {
     if (res.url === 'virtual:lyrics-ovh') {
        // Special case: we already have the lyrics! 
        // We'll pass them via session storage or window name
        window.lyricsToImport = res.content;
        window.open('about:blank', 'LyricsImporter', 'width=600,height=800');
     } else {
        window.open(res.url, 'LyricsImporter', 'width=600,height=800,menubar=no,location=no');
     }
  };

  const handleAddExternalVideo = (e) => {
    e.preventDefault();
    if (!videoUrl.trim()) return;

    let url = videoUrl.trim();
    let title = videoTitle.trim() || "External Video";
    let isVideo = true;
    let type = 'video';
    let isYouTube = false;
    let isVimeo = false;

    // Detect YouTube
    const ytMatch = url.match(/(?:https?:\/\/)?(?:www\.)?(?:youtube\.com\/(?:watch\?v=|embed\/)|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
    if (ytMatch) {
       url = `https://www.youtube.com/embed/${ytMatch[1]}?rel=0`;
       isYouTube = true;
       if (!videoTitle.trim()) title = "YouTube Video";
    }

    // Detect Vimeo
    const vimeoMatch = url.match(/(?:https?:\/\/)?(?:www\.)?(?:vimeo\.com\/|player\.vimeo\.com\/video\/)(\d+)/);
    if (vimeoMatch) {
       url = `https://player.vimeo.com/video/${vimeoMatch[1]}`;
       isVimeo = true;
       if (!videoTitle.trim()) title = "Vimeo Video";
    }

    if (!ytMatch && !vimeoMatch && !videoTitle.trim()) {
       try {
         const pathname = new URL(url).pathname;
         const filename = pathname.split('/').pop();
         if (filename) title = filename;
       } catch(e) {}
    }

    onSelectItem({
      title,
      url,
      isVideo,
      type,
      isYouTube,
      isVimeo,
      isExternal: true,
      id: url,
      filename: title
    });
  };

  const isInitialMount = useRef(true);
  useEffect(() => {
    if (isInitialMount.current) {
      isInitialMount.current = false;
      return;
    }
    if (!videoUrl.trim() || activeTab !== 'Videos') return;

    const fetchTitle = async () => {
      // Basic check for YT/Vimeo to avoid unnecessary fetches
      const isYT = videoUrl.includes('youtube.com') || videoUrl.includes('youtu.be');
      const isVimeo = videoUrl.includes('vimeo.com');

      if (!isYT && !isVimeo) return;

      setIsFetchingTitle(true);
      try {
        let endpoint = '';
        if (isYT) endpoint = `https://www.youtube.com/oembed?url=${encodeURIComponent(videoUrl)}&format=json`;
        if (isVimeo) endpoint = `https://vimeo.com/api/oembed.json?url=${encodeURIComponent(videoUrl)}`;

        const res = await fetch(endpoint);
        if (res.ok) {
           const data = await res.json();
           if (data.title) setVideoTitle(data.title);
        }
      } catch (err) {
        console.warn("Failed to fetch video title", err);
      } finally {
        setIsFetchingTitle(false);
      }
    };

    const timer = setTimeout(fetchTitle, 500);
    return () => clearTimeout(timer);
  }, [videoUrl, activeTab]);

  const handleGenericFileClick = async (fileObj) => {
    if (fileObj.isDirectory) {
        const imgArray = [];
        for await (const [name, handle] of fileObj.handle.entries()) {
             if (handle.kind === 'file' && name.match(/\.(jpg|jpeg|png|gif|webp)$/i)) {
                 const file = await handle.getFile();
                 imgArray.push({ name, url: URL.createObjectURL(file) });
             }
        }

        imgArray.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));

        onSelectItem({
            title: fileObj.name,
            type: 'slide_deck',
            images: imgArray.map(img => ({ url: img.url })),
            id: fileObj.name,
            folder: activeTab,
            filename: fileObj.name
        });
        return;
    }

    const fileHandle = fileObj.handle || fileObj;
    const file = await fileHandle.getFile();
    const url = URL.createObjectURL(file);
    const ext = file.name.split('.').pop().toLowerCase();

    let previewItem = {
      title: file.name,
      type: 'media',
      url: url,
      fileHandle: fileHandle,
      extension: ext,
      id: file.name,
      folder: activeTab, // Track which folder it came from
      filename: file.name
    };

    if (['jpg', 'jpeg', 'png', 'gif'].includes(ext)) {
       previewItem.images = [{ url }];
       previewItem.type = 'image';
    } else if (['mp4', 'webm', 'mov'].includes(ext)) {
       previewItem.isVideo = true;
       previewItem.type = 'video';
    } else if (['ppt', 'pptx', 'pdf', 'doc', 'docx', 'xls', 'xlsx', 'key', 'pages', 'numbers'].includes(ext)) {
       previewItem.isDocument = true;
       previewItem.type = 'document';
    } else if (['json'].includes(ext) && activeTab === 'Bible') {
       const text = await file.text();
       const rawData = JSON.parse(text);
       const parsedData = processBibleJson(rawData);
       previewItem = { ...parsedData, id: file.name, type: 'bible', folder: 'Bible', filename: file.name }; 
    }

    onSelectItem(previewItem);
  };

  // Reusable Add Button matching states
  const AddButton = () => (
    <button 
        onClick={triggerAddFeedback} 
        className={`w-full py-4 text-white font-extrabold tracking-wide uppercase rounded-xl border transition flex items-center justify-center gap-2 mt-auto shadow-lg flex-shrink-0 ${
           showAdded 
             ? 'bg-green-600 border-green-500 shadow-[0_0_20px_rgba(34,197,94,0.4)]' 
             : 'bg-neutral-800 hover:bg-neutral-700 active:bg-neutral-600 border-neutral-700/50'
        }`}
    >
        {showAdded ? <Check size={18} className="text-white" /> : <Plus size={18} className="text-blue-400" />} 
        {showAdded ? 'Added!' : 'Add to Service'}
    </button>
  );

  const checkInService = (idOrTitle) => serviceItems.some(i => 
    i.id === idOrTitle || 
    i.title === idOrTitle || 
    i.reference === idOrTitle ||
    i.filename === idOrTitle
  );

  const handleDeleteBibleFile = (e, file) => {
    e.stopPropagation();
    setBibleToDelete(file);
  };

  const confirmDeleteBible = async () => {
    if (!libraryHandle || !bibleToDelete) return;
    try {
        const dir = await libraryHandle.getDirectoryHandle('Bible');
      await dir.removeEntry(bibleToDelete.name);
      if (onDeleteItem) onDeleteItem(bibleToDelete.name);
      if (onRefresh) onRefresh();
      setBibleToDelete(null); // Close modal after successful deletion
    } catch(err) {
      alert("Failed to delete Bible file: " + err.message);
      setBibleToDelete(null); // Close modal even on error
    }
  };

  const confirmDeleteSong = async () => {
    if (!libraryHandle || !songToDelete) return;
    try {
      const dir = await libraryHandle.getDirectoryHandle('Songs');
      await dir.removeEntry(songToDelete.id);
      if (onDeleteItem) onDeleteItem(songToDelete.id);
      if (onRefresh) onRefresh();
      setSongToDelete(null);
    } catch(err) {
      alert("Failed to delete song: " + err.message);
      setSongToDelete(null);
    }
  };

  const handleDeleteSong = (e, song) => {
    e.stopPropagation();
    setSongToDelete(song);
  };

  const confirmDeleteGenericFile = async () => {
    if (!libraryHandle || !fileToDelete || !activeTab) return;
    try {
      const dir = await libraryHandle.getDirectoryHandle(activeTab);
      await dir.removeEntry(fileToDelete.name);
      if (onDeleteItem) onDeleteItem(fileToDelete.name);
      if (onRefresh) onRefresh();
      setFileToDelete(null);
    } catch(err) {
      alert("Failed to delete file: " + err.message);
      setFileToDelete(null);
    }
  };

  const handleDeleteGenericFile = (e, file) => {
    e.stopPropagation();
    setFileToDelete(file);
  };

  // 1. Service View
  if (activeTab === 'Service') {
    return (
      <div className="flex flex-col h-full w-full">
        <ServiceFlow 
          items={serviceItems} 
          onReorder={onServiceReorder} 
          onSelect={onSelectItem}           
          onRemove={onRemoveServiceItem}
          onUpdate={onUpdateServiceItem}
          onSave={onSaveService}
           onLoad={onLoadService}
           onClear={onClearService}
           liveItemId={liveItemId}
           playedItems={playedItems}
           onResetPlayed={onResetPlayed}
