import { useEffect, useState } from 'react';

/**
 * A hook that returns a monotonically increasing integer (`trigger`)
 * whenever the library directory changes. It utilizes the modern
 * FileSystemObserver API if available, or falls back to basic polling.
 */
export function useFileSystemWatcher(libraryHandle) {
  const [trigger, setTrigger] = useState(0);

  useEffect(() => {
    if (!libraryHandle) return;

    let observer;
    let interval;

    const setupObserver = async () => {
      try {
        if ('FileSystemObserver' in window) {
          observer = new window.FileSystemObserver((records) => {
            // Something changed (file added, modified, deleted)
            setTrigger(t => t + 1);
          });
          await observer.observe(libraryHandle, { recursive: true });
          console.log("FileSystemObserver attached to Halos Library.");
        } else {
          // Fallback recursive polling logic
          // A simple timer that prompts the consumer to check for updates.
          interval = setInterval(() => {
            setTrigger(t => t + 1);
          }, 5000);
          console.log("FileSystemObserver not found. Using polling fallback (5s).");
        }
      } catch (err) {
         console.warn("Watcher initialization failed, falling back to polling", err);
         interval = setInterval(() => setTrigger(t => t + 1), 5000);
      }
    };

    setupObserver();

    return () => {
      if (observer) observer.disconnect();
      if (interval) clearInterval(interval);
    };
  }, [libraryHandle]);

  const refresh = () => setTrigger(t => t + 1);

  return [trigger, refresh];
}

import { useState, useEffect } from 'react';

/**
 * Hook to generically list the files of any particular folder
 * whenever the user clicks that folder tab (e.g. Videos, Images, Documents).
 */
export function useFolderContents(libraryHandle, folderName, trigger) {
  const [files, setFiles] = useState([]);

  useEffect(() => {
    if (!libraryHandle || !folderName || folderName === 'Service' || folderName === 'Songs') {
       setFiles([]);
       return;
    }

    let isCancelled = false;

    const fetchFiles = async () => {
      try {
        const dirHandle = await libraryHandle.getDirectoryHandle(folderName, { create: true });
        const fileList = [];
        for await (const entry of dirHandle.values()) {
          if (entry.kind === 'file') {
             fileList.push({ name: entry.name, handle: entry, isDirectory: false });
          } else if (entry.kind === 'directory') {
             // Folders inside Images are treated as grouped Slide Decks!
             fileList.push({ name: entry.name, handle: entry, isDirectory: true });
          }
        }
        if (!isCancelled) {
           // Sort folders first, then alphabetically
           fileList.sort((a,b) => {
              if (a.isDirectory && !b.isDirectory) return -1;
              if (!a.isDirectory && b.isDirectory) return 1;
              return a.name.localeCompare(b.name, undefined, { numeric: true });
           });
           setFiles(fileList);
        }
      } catch(err) {
        console.warn(`Could not read generic folder: ${folderName}`);
      }
    };
    fetchFiles();

    return () => { isCancelled = true; };
  }, [libraryHandle, folderName, trigger]);

  return files;
}

import { useState, useEffect, useRef, useCallback } from 'react';
import Fuse from 'fuse.js';
import { get, set } from 'idb-keyval';
import { parseSongMarkdown } from '../utils/songParser';

const FUSE_OPTIONS = {
  keys: [
    { name: 'title', weight: 2 },
    { name: 'artist', weight: 1.5 },
    { name: 'ccli', weight: 1 },
    { name: 'lyrics', weight: 0.5 },
    { name: 'rawText', weight: 0.1 }
  ],
  includeMatches: true,
  threshold: 0.3,
  ignoreLocation: true, // CRITICAL for full-text search, otherwise matches deep in lyrics are ignored
  useExtendedSearch: true
};

/**
 * Hook to maintain a localized search index using Fuse.js.
 * Only re-reads and parses files that have changed based on lastModified timing.
 */
export function useSearchIndexer(libraryHandle, watcherTrigger) {
  const [isReady, setIsReady] = useState(false);
  const [results, setResults] = useState([]);
  const [query, setQuery] = useState('');

  const [indexedData, setIndexedData] = useState([]);
  const fuseRef = useRef(new Fuse([], FUSE_OPTIONS));
  const fileCacheRef = useRef(new Map()); // map of filename -> { lastModified }

  useEffect(() => {
    if (!libraryHandle) return;

    let isCancelled = false;

    const synchronizeIndex = async () => {
      try {
        const songsHandle = await libraryHandle.getDirectoryHandle('Songs', { create: true });
        let hasUpdates = false;
        let nextData = [...indexedData];

        // Load from idb on first mount
        if (!isReady && fileCacheRef.current.size === 0) {
          const cachedData = await get('halos-search-data-v2');
          const cachedMapArr = await get('halos-search-map-v2');
          if (cachedData && cachedMapArr) {
            nextData = cachedData;
            fileCacheRef.current = new Map(cachedMapArr);
            fuseRef.current = new Fuse(cachedData, FUSE_OPTIONS);
            setIndexedData(cachedData);
            setIsReady(true);
          }
        }

        const currentFiles = [];
        for await (const entry of songsHandle.values()) {
          if (entry.kind === 'file' && entry.name.endsWith('.md')) {
            currentFiles.push(entry);
          }
        }

        const currentFileNames = new Set(currentFiles.map(e => e.name));

        // Remove deleted files from index
        const initialLen = nextData.length;
        nextData = nextData.filter(d => currentFileNames.has(d.id));
        if (nextData.length !== initialLen) hasUpdates = true;

        for (const [name] of fileCacheRef.current.entries()) {
          if (!currentFileNames.has(name)) {
            fileCacheRef.current.delete(name);
          }
        }

        // Check for new or modified files
        for (const entry of currentFiles) {
          const file = await entry.getFile();
          const lastModified = file.lastModified;
          const name = entry.name;

          const cached = fileCacheRef.current.get(name);
          if (!cached || cached.lastModified !== lastModified) {
            const text = await file.text();
            const parsed = parseSongMarkdown(text);

            const rawLyrics = parsed.slides.map(s => s.content.join('\n')).join('\n\n');
            const doc = {
              id: name,
              title: parsed.metadata.title || name.replace('.md', ''),
              artist: parsed.metadata.artist || '',
              ccli: parsed.metadata.ccli || '',
              lyrics: rawLyrics,
              rawText: text,
              handle: entry
            };

            fileCacheRef.current.set(name, { lastModified });

            // Remove old version if it exists
            nextData = nextData.filter(d => d.id !== name);
            nextData.push(doc);
            hasUpdates = true;
          }
        }

        if (hasUpdates && !isCancelled) {
          fuseRef.current = new Fuse(nextData, FUSE_OPTIONS);
          setIndexedData(nextData);
          await set('halos-search-data-v2', nextData);
          await set('halos-search-map-v2', Array.from(fileCacheRef.current.entries()));
          if (!isReady) setIsReady(true);
        } else if (!isReady && !isCancelled) {
          setIsReady(true);
        }
      } catch (err) {
        console.warn("Failed to synchronize search index", err);
      }
    };

    synchronizeIndex();
  }, [libraryHandle, watcherTrigger]);

  const search = useCallback((searchQuery) => {
    setQuery(searchQuery);
    if (!searchQuery.trim()) {
      setResults([]);
      return;
    }
    const res = fuseRef.current.search(searchQuery).map(r => r.item);
    setResults(res);
  }, []);

  return { isReady, results, search, query, allItems: indexedData };
}

import { balanceLines } from '../utils/songParser';

/**
 * Fetches Bible passage from bible-api.com, caches the JSON payload 
 * locally in the `/Bible` directory, and parses the text into balanced slides.
 */
export async function fetchBiblePassage(libraryHandle, reference, translation = 'kjv') {
  const bibleFolder = await libraryHandle.getDirectoryHandle('Bible', { create: true });

  // Create a safe, normalized filename for the local cache
  const safeRef = reference.replace(/[^a-zA-Z0-9\s:]/g, '').replace(/[:\s]/g, '-').toLowerCase();
  const filename = `${translation}-${safeRef}.json`;

  try {
    // 1. Check local cache first (Offline capability)
    const fileHandle = await bibleFolder.getFileHandle(filename);
    const file = await fileHandle.getFile();
    const text = await file.text();
    console.log(`Loaded ${reference} from local /Bible cache!`);
    return processBibleJson(JSON.parse(text));
  } catch (err) {
    // File doesn't exist locally, we must fetch it from the API
  }

  try {
    // 2. Fetch from External Provider
    const res = await fetch(`https://bible-api.com/${encodeURIComponent(reference)}?translation=${translation}`);
    if (!res.ok) throw new Error("Passage not found");
    const data = await res.json();

    // 3. Save JSON cache to local File System
    const fileHandle = await bibleFolder.getFileHandle(filename, { create: true });
    const writable = await fileHandle.createWritable();
    await writable.write(JSON.stringify(data));
    await writable.close();

    return processBibleJson(data);
  } catch (err) {
    console.error("Bible fetch failed", err);
    throw err;
  }
}

/**
 * Parses a local book-based JSON structure (e.g. Genesis.json in /Bible/NIV/)
 */
export async function fetchLocalBiblePassage(libraryHandle, folderName, reference) {
  const bibleFolder = await libraryHandle.getDirectoryHandle('Bible');
  const transFolder = await bibleFolder.getDirectoryHandle(folderName);

  // Parse the reference into components. Supported formats:
  //   "Genesis 1"           ÔåÆ whole chapter
  //   "Genesis 1-3"         ÔåÆ chapter range
  //   "Genesis 1:5"         ÔåÆ single verse
  //   "Genesis 1:5-10"      ÔåÆ verse range (same chapter)
  //   "Genesis 1:13-2:10"   ÔåÆ cross-chapter verse range
  const parsed = parseReference(reference);
  if (!parsed) throw new Error("Invalid reference format. Try: Genesis 1, Genesis 1-2, Genesis 1:5-10, or Genesis 1:13-2:10");

  const { bookName } = parsed;

  // Find matching book file in the local translation folder
  let fileHandle;
  for await (const entry of transFolder.values()) {
    if (entry.kind === 'file' && entry.name.toLowerCase().includes(bookName.toLowerCase())) {
      fileHandle = entry;
      break;
    }
  }

  if (!fileHandle) throw new Error(`Book "${bookName}" not found in local ${folderName} folder`);

  const file = await fileHandle.getFile();
  const data = JSON.parse(await file.text());

  let allVerses = [];

  if (parsed.type === 'whole_chapter') {
    // e.g. "Genesis 1"
    const chapter = data.chapters.find(c => c.chapter.toString() === parsed.startChapter.toString());
    if (!chapter) throw new Error(`Chapter ${parsed.startChapter} not found in ${bookName}`);
    allVerses = chapter.verses;

  } else if (parsed.type === 'chapter_range') {
    // e.g. "Genesis 1-3"
    const startCh = parseInt(parsed.startChapter);
    const endCh = parseInt(parsed.endChapter);
    for (let ch = startCh; ch <= endCh; ch++) {
      const chapter = data.chapters.find(c => parseInt(c.chapter) === ch);
      if (chapter) allVerses.push(...chapter.verses);
    }

  } else if (parsed.type === 'verse_range_same') {
    // e.g. "Genesis 1:5" or "Genesis 1:5-10"
    const chapter = data.chapters.find(c => c.chapter.toString() === parsed.startChapter.toString());
    if (!chapter) throw new Error(`Chapter ${parsed.startChapter} not found in ${bookName}`);
    const start = parseInt(parsed.startVerse);
    const end = parsed.endVerse ? parseInt(parsed.endVerse) : start;
    allVerses = chapter.verses.filter(v => {
      const vn = parseInt(v.verse);
      return vn >= start && vn <= end;
    });

  } else if (parsed.type === 'cross_chapter') {
    // e.g. "Genesis 1:13-2:10"
    const startCh = parseInt(parsed.startChapter);
    const endCh = parseInt(parsed.endChapter);
    const startV = parseInt(parsed.startVerse);
    const endV = parseInt(parsed.endVerse);

    for (let ch = startCh; ch <= endCh; ch++) {
      const chapter = data.chapters.find(c => parseInt(c.chapter) === ch);
      if (!chapter) continue;

      let verses = chapter.verses;
      if (ch === startCh) {
        verses = verses.filter(v => parseInt(v.verse) >= startV);
      } else if (ch === endCh) {
        verses = verses.filter(v => parseInt(v.verse) <= endV);
      }
      allVerses.push(...verses);
    }
  }

  if (allVerses.length === 0) throw new Error("No verses found for this range");

  return processBibleJson({
    reference: reference,
    translation_id: folderName.toUpperCase(),
    verses: allVerses
  });
}

/**
 * Parses a Bible reference string into structured components.
 * Returns null if the format is not recognized.
 */
function parseReference(ref) {
  ref = ref.trim();

  // Cross-chapter verse range: "Genesis 1:13-2:10"
  let m = ref.match(/^(.+?)\s+(\d+):(\d+)\s*-\s*(\d+):(\d+)$/);
  if (m) return { bookName: m[1], type: 'cross_chapter', startChapter: m[2], startVerse: m[3], endChapter: m[4], endVerse: m[5] };

  // Verse range same chapter: "Genesis 1:5-10"
  m = ref.match(/^(.+?)\s+(\d+):(\d+)\s*-\s*(\d+)$/);
  if (m) return { bookName: m[1], type: 'verse_range_same', startChapter: m[2], startVerse: m[3], endVerse: m[4] };

  // Single verse: "Genesis 1:5"
  m = ref.match(/^(.+?)\s+(\d+):(\d+)$/);
  if (m) return { bookName: m[1], type: 'verse_range_same', startChapter: m[2], startVerse: m[3], endVerse: null };

  // Chapter range: "Genesis 1-2"
  m = ref.match(/^(.+?)\s+(\d+)\s*-\s*(\d+)$/);
  if (m) return { bookName: m[1], type: 'chapter_range', startChapter: m[2], endChapter: m[3] };

  // Whole chapter: "Genesis 1"
  m = ref.match(/^(.+?)\s+(\d+)$/);
  if (m) return { bookName: m[1], type: 'whole_chapter', startChapter: m[2] };

  return null;
}

export function processBibleJson(data) {
  // data format: { reference: 'John 3:16', translation_id: 'kjv', verses: [{ verse: 16, text: "..." }] }
  const slides = [];
  let slideIndex = 1;

  for (const v of data.verses) {
    // To ensure maximum 4 lines per slide, we must split the paragraph if it's too long
    // A heuristic: split sentences by punctuation + space.
    const rawLines = v.text
      .replace(/([.?!;")])\s+(?=[A-Z"'])/g, "$1\n")
      .split('\n')
      .map(l => l.trim())
      .filter(l => l !== '');

    // Fallback if the sentence itself is massive and didn't split (very rare in english bibles)
    // we just let CSS handle word-wrap, but balanceLines ensures the ARRAY length is balanced.

    const chunks = balanceLines(rawLines);
    chunks.forEach(chunk => {
      slides.push({
        type: `Verse ${v.verse}`,
        content: chunk,
        index: slideIndex++
      });
    });
  }

  return {
    reference: data.reference,
    translation: data.translation_id || 'KJV',
    slides
  };
}
